import{_ as a,o as r,c as d,ag as e}from"./chunks/framework.CxZWPeXl.js";const u=JSON.parse('{"title":"儀表板","description":"","frontmatter":{},"headers":[],"relativePath":"zh-TW/dashboard.md","filePath":"zh-TW/dashboard.md"}'),l={name:"zh-TW/dashboard.md"};function h(o,t,i,n,s,b){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="儀表板" tabindex="-1">儀表板 <a class="header-anchor" href="#儀表板" aria-label="Permalink to &quot;儀表板&quot;">​</a></h1><blockquote><p>一目了然掌握你的練習進度與學習成果</p></blockquote><h2 id="頁面概覽" tabindex="-1">頁面概覽 <a class="header-anchor" href="#頁面概覽" aria-label="Permalink to &quot;頁面概覽&quot;">​</a></h2><p>儀表板是登入後的首頁，提供個人學習概況與快速操作入口。頁面由上而下分為兩個區域：<strong>統計卡片區</strong> 與 <strong>近期練習紀錄</strong>。</p><h2 id="統計卡片區" tabindex="-1">統計卡片區 <a class="header-anchor" href="#統計卡片區" aria-label="Permalink to &quot;統計卡片區&quot;">​</a></h2><p>頁面上方顯示四張統計卡片：</p><h3 id="開始對話" tabindex="-1">開始對話 <a class="header-anchor" href="#開始對話" aria-label="Permalink to &quot;開始對話&quot;">​</a></h3><ul><li>點擊即可進入對話練習頁面，開始新的練習</li><li>描述文字：「點擊開始新的練習」</li></ul><h3 id="累積練習次數" tabindex="-1">累積練習次數 <a class="header-anchor" href="#累積練習次數" aria-label="Permalink to &quot;累積練習次數&quot;">​</a></h3><ul><li>顯示您截至目前為止完成的所有練習總次數</li><li>單位：<strong>次</strong></li><li>載入中時顯示 <code>--</code></li></ul><h3 id="對話總時間" tabindex="-1">對話總時間 <a class="header-anchor" href="#對話總時間" aria-label="Permalink to &quot;對話總時間&quot;">​</a></h3><ul><li>顯示您所有練習的累計對話時長</li><li>單位：<strong>小時</strong></li><li>由系統自動從所有練習紀錄的秒數彙總計算</li></ul><h3 id="連續練習的天數" tabindex="-1">連續練習的天數 <a class="header-anchor" href="#連續練習的天數" aria-label="Permalink to &quot;連續練習的天數&quot;">​</a></h3><ul><li>顯示您連續每日進行練習的天數紀錄</li><li>單位：<strong>天</strong></li><li>只要有一天未練習，連續紀錄就會重新計算</li></ul><h2 id="快速篩選" tabindex="-1">快速篩選 <a class="header-anchor" href="#快速篩選" aria-label="Permalink to &quot;快速篩選&quot;">​</a></h2><p>統計卡片下方提供三種快速篩選選項：</p><table tabindex="0"><thead><tr><th>選項</th><th>說明</th></tr></thead><tbody><tr><td>時鐘圖示（預設）</td><td>顯示最近 5 筆練習紀錄</td></tr><tr><td>今天</td><td>篩選出今日的練習紀錄</td></tr><tr><td>全部</td><td>跳轉至「練習歷史」頁面，查看完整紀錄</td></tr></tbody></table><h2 id="近期練習紀錄" tabindex="-1">近期練習紀錄 <a class="header-anchor" href="#近期練習紀錄" aria-label="Permalink to &quot;近期練習紀錄&quot;">​</a></h2><p>顯示最近的練習紀錄列表（預設最多 5 筆），每筆紀錄包含以下欄位：</p><table tabindex="0"><thead><tr><th>欄位</th><th>說明</th></tr></thead><tbody><tr><td>日期</td><td>練習進行的日期</td></tr><tr><td>年齡</td><td>客戶角色的年齡</td></tr><tr><td>性別</td><td>客戶角色的性別（男 / 女）</td></tr><tr><td>姓名</td><td>客戶角色的姓名</td></tr><tr><td>職業</td><td>客戶角色的職業</td></tr><tr><td>收入</td><td>客戶角色的收入等級</td></tr><tr><td>達成階段</td><td>該次練習最終達成的銷售階段</td></tr><tr><td>練習時長</td><td>該次練習的對話時長（分鐘）</td></tr></tbody></table><h3 id="操作按鈕" tabindex="-1">操作按鈕 <a class="header-anchor" href="#操作按鈕" aria-label="Permalink to &quot;操作按鈕&quot;">​</a></h3><p>每筆紀錄右側提供三個操作按鈕：</p><table tabindex="0"><thead><tr><th>按鈕</th><th>說明</th></tr></thead><tbody><tr><td>查看評量</td><td>前往該次練習的評量報告頁面</td></tr><tr><td>重新挑戰</td><td>使用相同的客戶角色設定，開始一次全新的練習</td></tr><tr><td>繼續練習</td><td>接續上次未完成的對話（僅限狀態為進行中的練習）</td></tr></tbody></table><h3 id="日期分組" tabindex="-1">日期分組 <a class="header-anchor" href="#日期分組" aria-label="Permalink to &quot;日期分組&quot;">​</a></h3><p>當同一天有多筆練習時，紀錄會依日期分組顯示，並標示「還有 N 筆，共 M 筆」的提示訊息。</p><h3 id="空白狀態" tabindex="-1">空白狀態 <a class="header-anchor" href="#空白狀態" aria-label="Permalink to &quot;空白狀態&quot;">​</a></h3><p>如果尚無任何練習紀錄，頁面會顯示「尚無練習紀錄」提示，引導您開始第一次練習。</p><hr><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li>開始 <a href="./practice.html">對話練習</a></li><li>了解 <a href="./evaluation.html">評量報告</a> 的評核內容</li><li>查看完整的 <a href="./history.html">練習歷史</a></li></ul>',30)])])}const p=a(l,[["render",h]]);export{u as __pageData,p as default};
